struct ProtocolPacket {
    uint32_t message_id;
    std::vector<uint16_t> data_values;
    uint32_t checksum;
};

std::vector<uint8_t> serialize_protocol_packet(const ProtocolPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a binary_stream object for writing
    hexi::binary_stream stream(buffer);

    // Convert message_id from native to big-endian and write
    auto converted_id = hexi::endian::native_to_big(packet.message_id);
    stream.write(&converted_id, sizeof(converted_id));

    // Convert each element in data_values from native to big-endian and write
    std::vector<uint16_t> converted_data;
    converted_data.reserve(packet.data_values.size());
    for (auto val : packet.data_values) {
        converted_data.push_back(hexi::endian::native_to_big(val));
    }
    stream.write_container(converted_data);

    // Convert checksum from native to big-endian and write
    auto converted_checksum = hexi::endian::native_to_big(packet.checksum);
    stream.write(&converted_checksum, sizeof(converted_checksum));

    return buffer;
}

ProtocolPacket deserialize_protocol_packet(const std::span<const uint8_t> buffer) {
    ProtocolPacket packet;

    // Create a binary_stream object for reading
    hexi::binary_stream stream(buffer);

    // Read message_id and convert from big-endian to native
    stream.read(&packet.message_id, sizeof(packet.message_id));
    packet.message_id = hexi::endian::big_to_native(packet.message_id);

    // Read count of data_values and convert from big-endian to native
    uint32_t count;
    stream.read(&count, sizeof(count));
    count = hexi::endian::big_to_native(count);

    // Resize vector and read data_values using read_container
    packet.data_values.resize(count);
    stream.read_container(packet.data_values);

    // Convert each element in data_values from big-endian to native
    for (auto& val : packet.data_values) {
        val = hexi::endian::big_to_native(val);
    }

    // Read checksum and convert from big-endian to native
    stream.read(&packet.checksum, sizeof(packet.checksum));
    packet.checksum = hexi::endian::big_to_native(packet.checksum);

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
    ProtocolHeader header;

    // Create a binary_stream object for reading
